import{_ as p,o as e,c as a,j as r,a as t,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"巫蛊师","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/通用及综合类/巫蛊师/巫蛊师.md","filePath":"4.资源分区/6.技艺及称号/通用及综合类/巫蛊师/巫蛊师.md"}'),s={name:"4.资源分区/6.技艺及称号/通用及综合类/巫蛊师/巫蛊师.md"};function o(d,b,l,_,i,c){return e(),a("div",null,[...b[0]||(b[0]=[r("h1",{id:"巫蛊师",tabindex:"-1"},[t("巫蛊师 "),r("a",{class:"header-anchor",href:"#巫蛊师","aria-label":'Permalink to "巫蛊师"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：新秩序006")])])],-1),n('<h1 id="巫蛊师-1" tabindex="-1">巫蛊师 <a class="header-anchor" href="#巫蛊师-1" aria-label="Permalink to &quot;巫蛊师&quot;">​</a></h1><p>巫蛊师</p><p>自久远的过去出现的一种职业，使用着巫蛊术，制造并役使着拥有各种力量的蛊物，以这些蛊物的力量来帮助他们实现各种各样人类力量所不能达成的事。巫蛊师依赖着蛊物的力量，蛊物也同样依赖着巫蛊师的力量来获得晋升，成为更强大的存在。巫蛊术实际上在长久的发展中分成了两个部分，使用精心炼制的蛊物，增强蛊物，使其发挥更强力量；使用临时祭炼将事物转变为简单的临时蛊物来使用。</p><p>蛊元：巫蛊师催动巫蛊术的能量，也是蛊物巫蛊力量的来源，它发自你的真灵，与你的生命力交融，具有与万物结合改变现实的力量。<br> 蛊元的关键属性是智力+操控。<br> 每天恢复能量上限的3倍，平均分配到每时每刻。<br> 蛊元是一个东西方通用能量池。</p><p>巫蛊术检定=操控+学识+专业：巫蛊术+辅助专业：炼蛊（手艺）+其他加值<br> 炼蛊检定=智力+手艺+专业：炼蛊+辅助专业：巫蛊术（学识）+其他加值</p><p>一转巫蛊师<br> D500<br> 描述：初步发掘自身真灵力量，但身体不净，血气污浊，真灵之力也不免染上些许色彩。<br> 血色蛊元：开启蛊元能量池。<br> 无求：自求自予，不为外累。你获得无需呼吸，无需睡眠，无需饮食的效果。使用自由动作消费1点蛊元，你可以免疫D级困难地形，可以在需要攀爬的表面正常行走，持续一场景。<br> 购买这一等级不会获得自由属性。</p><p>三转巫蛊师<br> C1000<br> 描述：食日饮月，纳清吐浊，赤色不显，印照日月。<br> 明净身：随着修炼，身净神明，纳入日精月华，真灵愈发强大，蛊元上限随最高内在支线等级提升(D5C7B9A11S13)。<br> 无缺：身心无缺，外邪不侵。蛊元能量池的无求特性提升为无缺，蛊元消耗可以提升至6点，除获得无求的效果外，还获得免疫毒素、免疫疾病，免疫诅咒、免疫影响心灵，都视为C级的免疫，持续一场景</p><p>五转巫蛊师<br> B2000<br> 描述：周天之内有五虫，蠃鳞毛羽昆。化五虫为五色，蠃为粉，鳞为青，毛为黄，羽为红，昆为玄。<br> 化万灵：日月生五虫，五虫生万灵，随着蛊元的自行运转演化，每过一影片蛊元能量池上限提升6点，巫蛊术相关检定获得1DP增强加值。</p><p>无漏：C级的无缺效果提升，不再消耗蛊元，变为被动效果。并且，免疫等级提高到B级，获得水面行走能力。</p><p>蛊物<br> 蛊师利用自身蛊元配合众多毒物，将众多自然界存在的生物，或特定物品进行炼制，最终得到的东西就叫作蛊，蛊分为独立作战的巨虫蛊，作为器具使用的器物蛊，与蛊师共生的附身蛊。此处仅写巨虫蛊，另外两种蛊物见巫蛊师的蛊术物品部分，蛊物以转数来区分强弱，这代表它被精心炼制获得根本性改变的次数。<br> 蛊物之毒分为六类，烈、郁、赤、寒、腐、幻六类。烈毒，凶暴猛烈，横死暴毙；郁毒，郁结于身，阻经断脉；赤毒，燥热如狂，焚肝灼脏；寒毒，寒凉彻骨，衰心僵化；腐毒，坏骨烂肉，身消化水；幻毒，杯蛇鬼车，神狂意乱。<br> 详细见器物蛊与巨虫蛊两个分页。</p><p>巫蛊术物品<br> 巫蛊虫袋 50<br> 体积1<br> 由巫蛊术炼制而成，内部空间比外表大得多，装有许多毒物。内部环境适合毒物生长繁衍，只需要持续从巫蛊师身上吸取些微蛊元就可以维持，只能用于在释放巫蛊术时自由动作放出任意数量的无支线普通毒虫来满足巫蛊术需求，不能被用于其他任何用途。</p><p>技能树<br> 基础巫蛊术<br> 500<br> 最基础粗陋的使用蛊元攻击的方法，将蛊元化作一道冲击打出，使用巫蛊术检定，攻击中获得3L武器伤害，对15米内单个目标造成等同成功数点力场严重伤害。</p><p>巫蛊诀窍<br> D500<br> 掌握巫蛊师中常见的施术与炼蛊技巧，以及最简单的蛊元使用方式。炼蛊与巫蛊术检定+3DP修行加值。</p><p>观世·启<br> D500<br> 用真灵代替自己的眼睛，从灵魂的角度，以上帝视角观察世界，寻常物质变为高透明度的模样，只余轮廓，直观地看到能量与灵魂的存在。这是一种新建的的非线性强感知方式，但不具有透视能力。</p><p>血饲·御<br> D500<br> 用秘法以蛊元饲喂巨虫蛊，临时增强其防御的基础方法，因低级蛊师的蛊元呈现赤色，古时又常以血为媒介，因此被称作血饲。标准动作花费2点蛊元发动秘法，通过接触强化蛊虫，增加3点力场防御和1点力场防御附加，并获得基于力场防御的【防能量】，持续一场景。仅能对一个巨虫蛊生效。</p><p>飞流壁<br> D500<br> 移动动作释放2点蛊元，强化、操控大量细小飞虫聚集环绕蛊师周围，分布稀疏不影响视野，当遇到攻击时，便会立刻聚集，主动迎击，形成抵御攻击的障壁，提供5点掩蔽防御和1点掩蔽防御附加成功，抵御攻击损耗的飞虫会被新引来的飞虫补充，持续一场景后虫群回到虫袋或散去。</p><p>巫蛊传承<br> C1000<br> 掌握具有一定历史的巫蛊家族，组织持续传承、研发、改良的高级巫蛊诀窍。巫蛊术检定增加1点修行附加成功，巫蛊术与炼蛊检定获得9加骰。</p><p>观世·灵<br> 前置：观世·启<br> C+1000<br> 真灵之力壮大，可洞见能量与灵魂的细微变动，轻易看穿粗浅的遮掩、欺骗之法，除了具有观世·启的效果外，同时具有透视，以及C级特异本质的侦测能力。</p><p>精炼·御<br> 差价升级，前置：血饲·御<br> C+1000<br> 蛊元融入日月精华，临时精炼蛊虫，使其更加顽强。使用标准动作，消耗6点蛊元，除血饲·御效果外，目标巨虫蛊获得【坚韧】特性，并且力场防御获得5点抵消破魔。仅能对一个巨虫蛊生效。</p><p>飞流壁·营垒<br> 差价升级，前置：飞流壁<br> C1500<br> 借由更加高妙的操控与快速炼制技巧，花费更多蛊元，提升屏障强度，与防护广度。使用移动动作，消耗增加到6点蛊元，飞虫的防护范围提升到半径3.75米，对友方单位与自身生效，掩蔽防御增加3点，并获得5点抵消威猛。</p><p>B级<br> 巫蛊秘传<br> B2000<br> 掌握具有悠久历史的巫蛊家族或组织的不传之秘。巫蛊术与炼蛊检定增加3点修行加值和2点修行附加成功，并且巫蛊术和炼蛊检定提升到8加骰。</p><p>观世·通<br> 差价升级，前置：观世·灵<br> B+2000<br> 融会贯通，能系统地掌握整个感知范围内的情况，见微知著，本能地追寻到任何不寻常之处。除了具有前置效果外，提供的侦测等级提升到B级，并获得B级免疫措手不及。</p><p>神通·御<br> 差价升级，前置：精炼·御<br> B+2000<br> 对巨虫蛊的临时增强到这个程度已经相当于让其多了一门神通。使用标准动作，消耗提升到10点蛊元，在前置效果中获得的力场防御提升2点，力场防御附加提升到2点，抵消破魔提升到10点，具有基于力场防御的【防弹】【防能量】，并给予蛊虫【超级坚韧】。仅能对一个巨虫蛊生效。</p><hr><p>Copyright ? 2023 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',25)])])}const D=p(s,[["render",o]]);export{f as __pageData,D as default};
